import React from "react";
import { Link, useLocation } from "react-router-dom";

const AdminNav = () => {
  const { pathname } = useLocation();
  const itemClass = (path) =>
    `px-3 py-2 rounded ${pathname === path ? "bg-black text-white" : "bg-gray-200"}`;
  return (
    <nav className="flex gap-2 flex-wrap mb-6">
      <Link className={itemClass("/admin")} to="/admin">Overview</Link>
      <Link className={itemClass("/admin/hospitals")} to="/admin/hospitals">Hospitals</Link>
      <Link className={itemClass("/admin/patients")} to="/admin/patients">Patients</Link>
      <Link className={itemClass("/admin/organs")} to="/admin/organs">Organs</Link>
      <Link className={itemClass("/admin/categories")} to="/admin/categories">Categories</Link>
      <Link className={itemClass("/admin/analytics")} to="/admin/analytics">Analytics</Link>
    </nav>
  );
};

export default AdminNav;
